mapper.select:
select c.id, c.course_name, c.week_day, c.grade_id, c.teacher_id, c.description, coalesce(c.location, '') as location, c.semester_id, c.del_flag, c.create_time,
       g.grade_name, coalesce(u.nick_name, c.teacher_name) as teacher_name, s.semester_name
       , q.quota, q.selected
from cou_course c
left join sys_grade g on c.grade_id = g.id
left join sys_user u on c.teacher_id = u.user_id
left join sys_semester s on c.semester_id = s.id

left join cou_class_quota q on c.id = q.course_id and q.class_id = #{classId} and q.del_flag = '0'

where c.del_flag = '0'


    AND c.course_name like #{courseNamePattern}


    AND c.week_day = #{weekDay}


    AND c.grade_id = #{gradeId}


    AND c.semester_id = #{semesterId}


    AND c.teacher_id = #{teacherId}



    AND c.location like #{locationPattern}

order by c.week_day asc, c.id asc

mapper.update:
update cou_course
course_name = #{courseName}, week_day = #{weekDay}, grade_id = #{gradeId}, teacher_id = #{teacherId}, teacher_id = null, teacher_name = #{teacherName}, teacher_name = null, description = #{description}, location = #{location}, location = null, semester_id = #{semesterId},
where id = #{id}
